import React from 'react'
import './Event.css'
import backgroundIMage from '../pics/images.jpg'
import {useState} from 'react'
import { useNavigate } from 'react-router-dom';
import close from "../pics/close.png"
import logo from '../pics/x.jpg'
const Event = ({loggedIn,usr}) => {
  const navigate = useNavigate();
  const [commenting,setCommenting]=useState(false)
  const [comments,setComments]=useState([
    {
      username:"user1",
      dp:logo,
      comments:"safsakjnksjfs"
    },
    {
      username:"user2",
      dp:logo,
      comments:"asdlnaskldf"
    },{
      username:"user3",
      dp:logo,
      comments:"asfklas"
    },{
      username:"user4",
      dp:logo,
      comments:"asfkaslmfsa"
    },{
      username:"user5",
      dp:logo,
      comments:"aslfnaskfs"
    },{
      username:"user6",
      dp:logo,
      comments:"asfkjsnskfjas"
    },{
      username:"user7",
      dp:logo,
      comments:"aslfnaskfas"
    },{
      username:"user8",
      dp:logo,
      comments:"asflkaslfkasmf"
    },{
      username:"user9s",
      dp:logo,
      comments:"saflsakmfs"
    },
  ])
  const addComment=()=>{
    console.log(comments)
    const comment=document.querySelector('.comment-input input')
    setComments([...comments,{username:usr.username,dp:usr.dp,comments:comment.value}])
    comment.value=''
  }
  return (
    <div className="event-main">
      <img src={backgroundIMage} className='eventBackgroundImg'  alt="" />
      <div className="event-content">
        <h2>Event NAme</h2>
        <h4>organized by: <span>Organizer</span></h4>
        <h4>BIO: <span>Lorem, ipsum dolor sit amet consectetur adipisicing elit. Ea, similique, maiores eligendi voluptatem libero obcaecati in nemo dignissimos autem quia, animi incidunt molestiae nulla aliquam excepturi aspernatur ad nobis nihil.
        Dolorem obcaecati velit voluptatem suscipit veritatis rerum fuga? Deleniti iusto similique hic cum distinctio magnam quo. Mollitia, eos. Nam sunt explicabo molestiae voluptate sapiente ad impedit sed ipsam eius architecto?</span></h4>
        <div className="interaction">
          <button onClick={()=>{setCommenting(true)}}>Comment</button>
          <button onClick={()=>{
            if(loggedIn){}
            else{navigate('/login')}
          }}>Like</button>
          <button onClick={()=>{
            if(loggedIn){}
            else{navigate('/login')}
          }}>Register</button>
        </div>

      </div>
    {commenting &&
      <div className="commentBox-background">
        <div className="commentBox">
          <h2 style={{fontSize:30+"px"}}>COMMENTS</h2>
          <div className="content">
            {comments.map((x)=>{
              return <div className="comment">
                <img src={x.dp} className='userDp' alt="" />
                <p>{x.comments}</p>

              </div>
            })}
          </div>
          <div className="comment-input">
            <input  type="text" />
            <button onClick={()=>{addComment()}}>Submit</button>
          </div>
        </div>
        <img src={close} className='close' onClick={()=>{setCommenting(false)}} alt="" />
      </div>
    }
    </div>
  )
}

export default Event
